const total = nums.reduce((sum, n) => sum + n, 0);
console.log(total);    // 15`,runnable:!0},{type:"challenge",prompt:"Write a function `sumPositive(arr)` that returns the sum of all positive numbers in the array.",starterCode:`function sumPositive(arr) {
